--- sys/netinet6/ip6_output.c	2 Feb 2008 14:11:31 -0000	1.114
+++ sys/netinet6/ip6_output.c	13 Mar 2008 21:43:05 -0000
@@ -1080,6 +1086,10 @@ done:
  	} else if (ro_pmtu == &ip6route && ro_pmtu->ro_rt) {
  		RTFREE(ro_pmtu->ro_rt);
  	}
+#ifdef IPSEC
+	if (sp != NULL)
+		KEY_FREESP(&sp);
+#endif

  	return (error);

